SELECT student_id, subject, score,
       RANK() OVER (PARTITION BY subject ORDER BY score DESC) AS position
FROM exam_results;

const scores = [{id: 1, score: 95}, {id: 2, score: 85}, {id: 3, score: 95}];
const sorted = [...scores].sort((a,b) => b.score - a.score);
const ranked = sorted.map((s, i) => ({...s, rank: i+1}));

List<Integer> scores = Arrays.asList(95, 85, 95, 78);
List<Integer> sorted = scores.stream().sorted(Collections.reverseOrder()).collect(Collectors.toList());
for (int i = 0; i < sorted.size(); i++) {
    System.out.println((i + 1) + ": " + sorted.get(i));
}
